package com.example.shareapp; // Replace with your actual package name

import android.app.Activity;
import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.view.View;
import android.widget.ImageView;
import android.widget.TextView;
import java.util.ArrayList;

public class ShareReceiverActivity extends Activity {

    private ImageView sharedImageView;
    private TextView sharedTextView;
    private TextView sharedContentLabel;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_share_receiver);

        sharedImageView = findViewById(R.id.sharedImageView);
        sharedTextView = findViewById(R.id.sharedTextView);
        sharedContentLabel = findViewById(R.id.sharedContentLabel);

        Intent intent = getIntent();
        String action = intent.getAction();
        String type = intent.getType();

        if (Intent.ACTION_SEND.equals(action) && type != null) {
            handleSendIntent(intent, type);
        } else if (Intent.ACTION_SEND_MULTIPLE.equals(action) && type != null) {
            handleSendMultipleIntent(intent, type);
        } else {
            // No specific share data or an unsupported intent action
            sharedContentLabel.setText("No Share Content Received");
            sharedTextView.setVisibility(View.VISIBLE);
            sharedTextView.setText("This activity is designed to receive content shared from other apps (images and text).");
        }
    }

    private void handleSendIntent(Intent intent, String type) {
        if ("text/plain".equals(type)) {
            String sharedText = intent.getStringExtra(Intent.EXTRA_TEXT);
            if (sharedText != null) {
                sharedTextView.setText("Shared Text:\n" + sharedText);
                sharedTextView.setVisibility(View.VISIBLE);
            } else {
                sharedTextView.setText("No text content found in share intent.");
                sharedTextView.setVisibility(View.VISIBLE);
            }
        } else if (type.startsWith("image/")) {
            Uri imageUri = intent.getParcelableExtra(Intent.EXTRA_STREAM);
            if (imageUri != null) {
                sharedImageView.setImageURI(imageUri);
                sharedImageView.setVisibility(View.VISIBLE);
                sharedTextView.setText("Shared Image (URI: " + imageUri.toString() + ")");
                sharedTextView.setVisibility(View.VISIBLE);
            } else {
                sharedTextView.setText("No image content found in share intent.");
                sharedTextView.setVisibility(View.VISIBLE);
            }
        } else {
            sharedTextView.setText("Unsupported single shared content type: " + type);
            sharedTextView.setVisibility(View.VISIBLE);
        }
    }

    private void handleSendMultipleIntent(Intent intent, String type) {
        ArrayList<Uri> streamUris = intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM);

        if (streamUris != null && !streamUris.isEmpty()) {
            if (type.startsWith("image/")) {
                // For multiple images, display the first and list all URIs
                sharedImageView.setImageURI(streamUris.get(0));
                sharedImageView.setVisibility(View.VISIBLE);

                StringBuilder uriListText = new StringBuilder("Shared " + streamUris.size() + " images. Displaying the first one.\n\nURIs:\n");
                for (Uri uri : streamUris) {
                    uriListText.append(uri.toString()).append("\n");
                }
                sharedTextView.setText(uriListText.toString());
                sharedTextView.setVisibility(View.VISIBLE);

            } else if ("text/plain".equals(type)) {
                // For multiple text files (shared as URIs), try to combine their contents or list URIs
                StringBuilder combinedText = new StringBuilder("Shared " + streamUris.size() + " text items.\n\n");
                for (int i = 0; i < streamUris.size(); i++) {
                    Uri uri = streamUris.get(i);
                    combinedText.append("Item ").append(i + 1).append(" URI: ").append(uri.toString()).append("\n");
                    // To actually read the content from each text URI, you'd use ContentResolver:
                    /*
                    try (InputStream inputStream = getContentResolver().openInputStream(uri);
                         BufferedReader reader = new BufferedReader(new InputStreamReader(inputStream))) {
                        String line;
                        while ((line = reader.readLine()) != null) {
                            combinedText.append(line).append("\n");
                        }
                        combinedText.append("---\n"); // Separator for multiple texts
                    } catch (Exception e) {
                        combinedText.append(" (Error reading: ").append(e.getMessage()).append(")\n");
                    }
                    */
                }
                sharedTextView.setText(combinedText.toString() + "\n(Note: Direct text content not extracted in this demo for multiple text files, only URIs are listed.)");
                sharedTextView.setVisibility(View.VISIBLE);
            } else {
                sharedTextView.setText("Unsupported multiple shared content type with URIs: " + type);
                sharedTextView.setVisibility(View.VISIBLE);
            }
        } else {
            // Fallback for ACTION_SEND_MULTIPLE if EXTRA_STREAM is null or empty,
            // or if it's a combined text scenario not typically using EXTRA_STREAM.
            String sharedText = intent.getStringExtra(Intent.EXTRA_TEXT);
            if (sharedText != null) {
                sharedTextView.setText("Shared multiple texts (possibly combined into one):\n" + sharedText);
                sharedTextView.setVisibility(View.VISIBLE);
            } else {
                sharedTextView.setText("No multiple shared content found for type: " + type);
                sharedTextView.setVisibility(View.VISIBLE);
            }
        }
    }
}